solution_code:
#include <iostream>

int main()
{
    int celsius = 0;
    std::cin >> celsius;

    int fahrenheit = celsius * 9 / 5 + 32;
    std::cout << celsius << " C = " << fahrenheit << " F" << '\n';

    return 0;
}

