solution_code:
#include <iostream>

int divide_report(int dividend, int divisor)
{
    return dividend / divisor;
}

int main()
{
    int dividend = 0;
    int divisor = 0;
    std::cin >> dividend >> divisor;

    int quotient = divide_report(dividend, divisor);
    int remainder = dividend % divisor;

    std::cout << "Quotient: " << quotient << '\n';
    std::cout << "Remainder: " << remainder << '\n';

    return 0;
}
